from pathlib import Path

path = Path(__file__).with_name('agent_live_windows_followup_testsfix.py')
content = path.read_text(encoding='utf-8')
old = 'content = replace_regex(\n'
if content.count(old) != 1:
    raise RuntimeError(f'expected one undefined replace_regex call, found {content.count(old)}')
content = content.replace(old, 'content = remove_regex(\n', 1)
marker = "\n\nfor root_name in ('tests', 'scripts'):\n"
if content.count(marker) != 1:
    raise RuntimeError('final evidence scan marker changed unexpectedly')
patch = '''\n\n# Remove the legacy safe-position field from combat browser evidence.\npath = 'tests/combat-tactical-integration.spec.ts'\ncontent = read(path)\ncontent = remove_exact(content, '  bestSafePosition: { x: number; y: number } | null;\\n', 'combat browser safe-position field')\ncontent = remove_exact(content, '    expect(snapshot.bestSafePosition).not.toBeNull();\\n', 'combat browser safe-position assertions')\ncontent = replace_exact(content, "  test('real visual contact appears in the existing danger, safe-position and route views', async ({ page }, testInfo) => {", "  test('real visual contact appears in the existing danger and route views', async ({ page }, testInfo) => {", 'combat visual-contact title')\ncontent = replace_exact(content, "  test('reverse slope changes the safe-position and routed movement context', async ({ page }, testInfo) => {", "  test('reverse slope changes the danger and routed movement context', async ({ page }, testInfo) => {", 'combat reverse-slope title')\ncontent = replace_exact(content, "combat-stage1-04-reverse-slope-safe-route.png", "combat-stage1-04-reverse-slope-danger-route.png", 'combat reverse-slope screenshot name')\nwrite(path, content)\n\n\n# Preserve cover-cache verification with a fixed wall probe instead of a selected safe-position winner.\npath = 'scripts/danger_layer_performance_smoke.ts'\ncontent = read(path)\ncontent = replace_exact(content, "const baseline = buildSoldierAwarenessReport(state, blue);\\nconst baselineWinner = baseline.bestSafePositions[0];\\nassert.ok(baselineWinner, 'baseline must expose a safe-position winner');\\n", "buildSoldierAwarenessReport(state, blue);\\n", 'danger smoke baseline winner')\ncontent = remove_exact(content, "const firstWinner = first.bestSafePositions[0];\\nassert.ok(firstWinner, 'directional threat must expose a safe-position winner');\\nassert.ok(\\n  firstWinner.position.x < WALL_X,\\n  `eastern directional threat must select the west/protected wall side (winner x=${firstWinner.position.x})`,\\n);\\nassert.equal(firstWinner.protectedAgainstThreatId, THREAT_ID);\\nassert.notDeepEqual(firstWinner.position, baselineWinner.position);\\n", 'danger smoke winner assertions')\ncontent = replace_exact(content, "const coldBuildMs = diagnostics.lastBuildMs;\\n", "const coldBuildMs = diagnostics.lastBuildMs;\\nconst protectedProbePosition = { x: WALL_X - 1.5, y: 100.5 };\\n", 'danger smoke fixed probe')\ncontent = remove_exact(content, "  firstWinner.position,\\n", 'danger smoke winner probe references')\ncontent = replace_exact(content, "  'Danger layer performance smoke passed: dynamic threat changes reuse bounded object/forest and directional terrain geometry while preserving wall-side semantics.'", "  'Danger layer performance smoke passed: dynamic threat changes reuse bounded object/forest and directional terrain geometry while preserving cache semantics.'", 'danger smoke completion text')\ncontent = content.replace("  { x: threat.x, y: threat.y },\\n  blue.behaviorRuntime.posture,", "  { x: threat.x, y: threat.y },\\n  protectedProbePosition,\\n  blue.behaviorRuntime.posture,")\nwrite(path, content)\n'''
content = content.replace(marker, patch + marker, 1)
path.write_text(content, encoding='utf-8')
print('Corrected evidence helper, removed combat safe-position evidence, and replaced winner probes.')
